1045	The transition data of \cref{sec:gr_transition} lives at the level of rings. To
1046	feed it to a scheme-gluing machine we must re-express each piece as a morphism in
1047	the category of schemes: the charts \(U^I\), the principal-open overlaps
1048	\(U^I_J\), their inclusions, and the transitions \(\theta_{I,J}\) all become
1049	schemes and scheme morphisms by applying the contravariant functor \(\Spec\).
1050	The lemmas of this section record those translations together with the two
1051	genuinely geometric facts needed to assemble a glue datum: that each inclusion
1052	\(U^I_J \hookrightarrow U^I\) is an open immersion, and that the fibre product of
1053	two principal opens of \(\Spec A\) is again a principal open. They are
1054	project-internal bridge results with no external source beyond the gluing
1055	construction of \cref{def:gr_glued_scheme}.
1056	
1057	\subsection*{Mathlib inputs for the scheme-level layer}
1058	
1059	\begin{lemma}
1060	[\(\Spec\) of an away-localisation is an open immersion]
1061	  \label{lem:mathlib_specMap_localizationAway_isOpenImmersion}
1062	  \lean{AlgebraicGeometry.Scheme.isOpenImmersion_SpecMap_localizationAway}
1063	  \mathlibok
1064	  \textit{Provided by Mathlib.}
1065	  Let \(R\) be a commutative ring and \(f \in R\). The morphism
1066	  \(\Spec R[1/f] \to \Spec R\) induced by the structure map \(R \to R[1/f]\) of
1067	  the away-localisation is an open immersion (onto the basic open
1068	  \(D(f) \subseteq \Spec R\)).
1069	\end{lemma}
1070	
1071	\begin{lemma}
1072	[Fibre product of two affine spectra is \(\Spec\) of the tensor product]
1073	  \label{lem:mathlib_pullbackSpecIso}
1074	  \lean{AlgebraicGeometry.pullbackSpecIso}
1075	  \mathlibok
1076	  \textit{Provided by Mathlib.}
1077	  Let \(R\) be a commutative ring and \(S\), \(T\) two \(R\)-algebras. The fibre
1078	  product of \(\Spec S \to \Spec R \leftarrow \Spec T\) is canonically isomorphic
1079	  to the spectrum of the tensor product:
1080	  \[
1081	    \Spec S \times_{\Spec R} \Spec T \;\cong\; \Spec\bigl(S \otimes_R T\bigr).
1082	  \]
1083	\end{lemma}
1084	
1085	\begin{lemma}
1086	[An away-localisation of a tensor product is a double away-localisation]
1087	  \label{lem:mathlib_isLocalization_away_mul}
1088	  \lean{IsLocalization.Away.mul'}
1089	  \mathlibok
1090	  \textit{Provided by Mathlib.}
1091	  Let \(R\) be a commutative ring, \(x, y \in R\), and \(R[1/x]\) the localisation
1092	  away from \(x\). Then \(R[1/x] \otimes_R R[1/y]\) is a localisation of \(R\)
1093	  away from \(x y\); equivalently it realises \(R[1/(xy)]\).
1094	\end{lemma}
1095	
1096	\begin{lemma}
1097	[Two away-localisations of the same element are canonically isomorphic]
1098	  \label{lem:mathlib_isLocalization_algEquiv}
1099	  \lean{IsLocalization.algEquiv}
1100	  \mathlibok
1101	  \textit{Provided by Mathlib.}
1102	  Let \(R\) be a commutative ring and \(M \subseteq R\) a submonoid. Any two
1103	  localisations of \(R\) at \(M\) are uniquely \(R\)-algebra isomorphic; in
1104	  particular, given two rings each presented as \(R[1/x]\) there is a canonical
1105	  \(R\)-algebra isomorphism between them.
1106	\end{lemma}
1107	
1108	\subsection*{Charts, overlaps, and inclusions as schemes}
1109	
1110	\begin{theorem}
1111	
1112	\leanok
1113	[The diagonal minor is the unit]
1114	  \label{lem:gr_minorDet_self}
1115	  \lean{AlgebraicGeometry.Grassmannian.minorDet_self}
1116	  \uses{def:gr_minor_det, lem:gr_universalMatrix_submatrix_self}
1117	  For every size-\(d\) subset \(I\), the \(I\)-minor determinant of the universal
1118	  matrix \(X^I\) is the unit of the chart ring:
1119	  \[
1120	    P^I_I \;=\; 1 \;\in\; R^I.
1121	  \]
1122	\end{theorem}
1123	\begin{proof}
1124	  \uses{def:gr_minor_det, lem:gr_universalMatrix_submatrix_self}
1125	  \leanok
1126	  The \(I\)-minor \(X^I_I\) is the \(d \times d\) identity
1127	  (\cref{lem:gr_universalMatrix_submatrix_self}), and \(\det(1_{d\times d}) = 1\).
1128	  Proved directly in Lean.
1129	\end{proof}
1130	
1131	\begin{definition}
1132	
1133	\leanok
1134	[The overlap scheme \(U^I_J\)]
1135	  \label{def:gr_chart_overlap}
1136	  \lean{AlgebraicGeometry.Grassmannian.chartOverlap}
1137	  \uses{def:gr_minor_det, def:gr_affine_chart}
1138	  The principal-open overlap, as a scheme, is the affine spectrum of the
1139	  away-localisation of the chart ring \(R^I\) (\cref{def:gr_affine_chart}) at the
1140	  minor determinant \(P^I_J\) (\cref{def:gr_minor_det}):
1141	  \[
1142	    U^I_J \;:=\; \Spec R^I[1/P^I_J].
1143	  \]
1144	  It is the \(V\)-object of the Grassmannian glue datum.
1145	\end{definition}
1146	
1147	\begin{definition}
1148	
1149	\leanok
1150	[The overlap inclusion \(U^I_J \to U^I\)]
1151	  \label{def:gr_chart_incl}
1152	  \lean{AlgebraicGeometry.Grassmannian.chartIncl}
1153	  \uses{def:gr_chart_overlap, def:gr_affine_chart}
1154	  The canonical inclusion of the overlap into the chart is the \(\Spec\) of the
1155	  structure map \(R^I \to R^I[1/P^I_J]\):
1156	  \[
1157	    U^I_J \;=\; \Spec R^I[1/P^I_J] \longrightarrow \Spec R^I \;=\; U^I .
1158	  \]
1159	  It is the \(f\)-field of the Grassmannian glue datum.
1160	\end{definition}
1161	
1162	\begin{lemma}
1163	
1164	\leanok
1165	[The overlap inclusion is an open immersion]
1166	  \label{lem:gr_chartIncl_isOpenImmersion}
1167	  \lean{AlgebraicGeometry.Grassmannian.chartIncl_isOpenImmersion}
1168	  \uses{def:gr_chart_incl, lem:mathlib_specMap_localizationAway_isOpenImmersion}
1169	  The inclusion \(U^I_J \hookrightarrow U^I\) (\cref{def:gr_chart_incl}) is an
1170	  open immersion, identifying \(U^I_J\) with the basic open \(D(P^I_J)\) of
1171	  \(U^I\).
1172	\end{lemma}
1173	\begin{proof}
1174	  \uses{def:gr_chart_incl, lem:mathlib_specMap_localizationAway_isOpenImmersion}
1175	  \leanok
1176	  This is exactly the away-localisation open-immersion fact
1177	  (\cref{lem:mathlib_specMap_localizationAway_isOpenImmersion}) applied to
1178	  \(f = P^I_J\). Proved directly in Lean.
1179	\end{proof}
1180	
1181	\begin{lemma}
1182	
1183	\leanok
1184	[The self-overlap inclusion is an isomorphism]
1185	  \label{lem:gr_chartIncl_self_isIso}
1186	  \lean{AlgebraicGeometry.Grassmannian.chartIncl_self_isIso}
1187	  \uses{def:gr_chart_incl, lem:gr_minorDet_self}
1188	  For every \(I\), the self-inclusion \(U^I_I \to U^I\) (\cref{def:gr_chart_incl})
1189	  is an isomorphism. This is the \(f_{\mathrm{id}}\)-field of the glue datum.
1190	\end{lemma}
1191	\begin{proof}
1192	  \uses{def:gr_chart_incl, lem:gr_minorDet_self}
1193	  \leanok
1194	  Since \(P^I_I = 1\) is a unit (\cref{lem:gr_minorDet_self}), the structure map
1195	  \(R^I \to R^I[1/P^I_I]\) is the localisation at a unit, hence an isomorphism of
1196	  rings; applying \(\Spec\) gives an isomorphism of schemes. Proved directly in
1197	  Lean.
1198	\end{proof}
1199	
1200	\begin{definition}
1201	
1202	\leanok
1203	[The scheme-level transition \(U^I_J \to U^J_I\)]
1204	  \label{def:gr_chart_transition}
1205	  \lean{AlgebraicGeometry.Grassmannian.chartTransition}
1206	  \uses{def:gr_transition, def:gr_chart_overlap}
1207	  The scheme-level transition is the \(\Spec\) of the ring transition map
1208	  \(\theta_{I,J} : R^J[1/P^J_I] \to R^I[1/P^I_J]\) (\cref{def:gr_transition}):
1209	  \[
1210	    U^I_J \;=\; \Spec R^I[1/P^I_J] \longrightarrow \Spec R^J[1/P^J_I] \;=\; U^J_I .
1211	  \]
1212	  It is the \(t\)-field of the Grassmannian glue datum.
1213	\end{definition}
1214	
1215	\begin{lemma}
1216	
1217	\leanok
1218	[The self-transition is the identity]
1219	  \label{lem:gr_chartTransition_self}
1220	  \lean{AlgebraicGeometry.Grassmannian.chartTransition_self}
1221	  \uses{def:gr_chart_transition, lem:gr_transition_self}
1222	  For every \(I\), the scheme-level self-transition
1223	  \(U^I_I \to U^I_I\) (\cref{def:gr_chart_transition}) is the identity. This is
1224	  the \(t_{\mathrm{id}}\)-field of the glue datum.
1225	\end{lemma}
1226	\begin{proof}
1227	  \uses{def:gr_chart_transition, lem:gr_transition_self}
1228	  \leanok
1229	  By \cref{lem:gr_transition_self} the ring map \(\theta_{I,I}\) is the identity,
1230	  and \(\Spec\) sends the identity ring map to the identity morphism. Proved
1231	  directly in Lean.
1232	\end{proof}
1233	
1234	\subsection*{The away-localisation pullback isomorphism}
1235	
1236	\begin{definition}
1237	
1238	\leanok
1239	[Pullback of two principal opens of \(\Spec A\)]
1240	  \label{def:gr_away_pullback_iso}
1241	  \lean{AlgebraicGeometry.Grassmannian.awayPullbackIso}
1242	  \uses{lem:mathlib_pullbackSpecIso, lem:mathlib_isLocalization_away_mul, lem:mathlib_isLocalization_algEquiv}
1243	  Let \(A\) be a commutative ring and \(x, y \in A\). The fibre product of the two
1244	  basic-open inclusions \(\Spec A[1/x] \to \Spec A \leftarrow \Spec A[1/y]\) is
1245	  canonically isomorphic to the spectrum of the doubly-inverted localisation:
1246	  \[
1247	    \Spec A[1/x] \times_{\Spec A} \Spec A[1/y]
1248	      \;\cong\; \Spec A[1/(xy)].
1249	  \]
1250	  The isomorphism is the composite of the tensor-product identification of the
1251	  pullback (\cref{lem:mathlib_pullbackSpecIso}) with the \(\Spec\) of the
1252	  localisation isomorphism
1253	  \(A[1/x] \otimes_A A[1/y] \cong A[1/(xy)]\)
1254	  (\cref{lem:mathlib_isLocalization_away_mul},
1255	  \cref{lem:mathlib_isLocalization_algEquiv}). It is stated over a general base
1256	  ring \(A\) so that it may be instantiated at the triple-overlap rings of the
1257	  Grassmannian glue datum.
1258	\end{definition}
1259	
1260	\begin{lemma}
1261	
1262	\leanok
1263	[Left leg of the pullback isomorphism]
1264	  \label{lem:gr_awayPullbackIso_inv_fst}
1265	  \lean{AlgebraicGeometry.Grassmannian.awayPullbackIso_inv_fst}
1266	  \uses{def:gr_away_pullback_iso, def:gr_away_incl_left}
1267	  Under the identification of \cref{def:gr_away_pullback_iso}, the first
1268	  projection of the pullback corresponds to the left away-inclusion: the
1269	  composite
1270	  \(\Spec A[1/(xy)] \to \Spec A[1/x] \times_{\Spec A} \Spec A[1/y]
1271	    \xrightarrow{\mathrm{pr}_1} \Spec A[1/x]\)
1272	  equals \(\Spec\) of the inclusion \(\iota^{\mathrm{L}}_{x,y}\)
1273	  (\cref{def:gr_away_incl_left}).
1274	\end{lemma}
1275	\begin{proof}
1276	  \uses{def:gr_away_pullback_iso, def:gr_away_incl_left}
1277	  \leanok
1278	  The pullback-projection compatibility of the tensor-product identification
1279	  sends \(\mathrm{pr}_1\) to the left tensor inclusion, which under the
1280	  localisation isomorphism is the structure map \(A[1/x] \to A[1/(xy)]\), i.e.\
1281	  \(\iota^{\mathrm{L}}_{x,y}\); the verification is the universal property of the
1282	  away-localisation. Proved directly in Lean.
1283	\end{proof}
1284	
1285	\begin{lemma}
1286	
1287	\leanok
1288	[Right leg of the pullback isomorphism]
1289	  \label{lem:gr_awayPullbackIso_inv_snd}
1290	  \lean{AlgebraicGeometry.Grassmannian.awayPullbackIso_inv_snd}
1291	  \uses{def:gr_away_pullback_iso, def:gr_away_incl_right}
1292	  Symmetrically, the second projection of the pullback corresponds to the right
1293	  away-inclusion: the composite
1294	  \(\Spec A[1/(xy)] \to \Spec A[1/x] \times_{\Spec A} \Spec A[1/y]
1295	    \xrightarrow{\mathrm{pr}_2} \Spec A[1/y]\)
1296	  equals \(\Spec\) of \(\iota^{\mathrm{R}}_{x,y}\)
1297	  (\cref{def:gr_away_incl_right}).
1298	\end{lemma}
1299	\begin{proof}
1300	  \uses{def:gr_away_pullback_iso, def:gr_away_incl_right}
1301	  \leanok
1302	  As in \cref{lem:gr_awayPullbackIso_inv_fst}, with the right tensor inclusion in
1303	  place of the left. Proved directly in Lean.
1304	\end{proof}
1305	
1306	\begin{definition}
1307	
1308	\leanok
1309	[Order-swap isomorphism \(A[1/(xy)] \cong A[1/(yx)]\)]
1310	  \label{def:gr_away_mul_comm_equiv}
1311	  \lean{AlgebraicGeometry.Grassmannian.awayMulCommEquiv}
1312	  \uses{lem:mathlib_isLocalization_algEquiv}
1313	  For \(x, y \in A\), the canonical ring isomorphism
1314	  \[
1315	    A[1/(xy)] \;\cong\; A[1/(yx)]
1316	  \]
1317	  identifying the two away-localisations, which agree because \(xy\) and \(yx\)
1318	  generate the same submonoid of \(A\)
1319	  (\cref{lem:mathlib_isLocalization_algEquiv}). It is inserted into the
1320	  triple-cocycle field of the glue datum to reconcile the opposite product
1321	  orders produced by the two pullback isomorphisms.
1322	\end{definition}
1323	
1324	\begin{lemma}
1325	[The order-swap lies over the base ring]
1326	  \label{lem:gr_awayMulCommEquiv_comp_algebraMap}
1327	  \lean{AlgebraicGeometry.Grassmannian.awayMulCommEquiv_comp_algebraMap}
1328	  \uses{def:gr_away_mul_comm_equiv, lem:mathlib_isLocalization_algEquiv}
1329	  The order-swap isomorphism (\cref{def:gr_away_mul_comm_equiv}) intertwines the
1330	  two structure maps: for \(x, y \in A\),
1331	  \[
1332	    \mathrm{swap}_{x,y} \circ \bigl(A \to A[1/(xy)]\bigr)
1333	      \;=\; \bigl(A \to A[1/(yx)]\bigr).
1334	  \]
1335	\end{lemma}
1336	\begin{proof}
1337	  \uses{def:gr_away_mul_comm_equiv, lem:mathlib_isLocalization_algEquiv}
1338	  Both \(A[1/(xy)]\) and \(A[1/(yx)]\) are localisations of \(A\) at the same
1339	  submonoid (\(xy\) and \(yx\) generate it), and the canonical comparison map
1340	  between two such localisations is an \(A\)-algebra isomorphism
1341	  (\cref{lem:mathlib_isLocalization_algEquiv}); an \(A\)-algebra map commutes with
1342	  the structure maps. Proved directly in Lean.
1343	\end{proof}
1344	
1345	\subsection*{The triple-overlap glue field \(t'\)}
1346	
1347	The scheme-gluing machine requires, beyond the pairwise transitions \(t_{I,J}\), a
1348	\emph{triple-overlap} field \(t'\) on the relevant fibre products, together with
1349	its compatibility \(t_{\mathrm{fac}}\) with the chart projections. We record both
1350	as the next layer of bridge results; their cocycle coherence is the residual
1351	obligation discharged in \cref{def:gr_glued_scheme}.
1352	
1353	\begin{definition}
1354	[The triple-overlap transition \(t'\)]
1355	  \label{def:gr_chart_transition'}
1356	  \lean{AlgebraicGeometry.Grassmannian.chartTransition'}
1357	  \uses{def:gr_away_pullback_iso, def:gr_cocycle_theta_ij, def:gr_away_mul_comm_equiv}
1358	  The \(t'\)-field of the Grassmannian glue datum is the morphism of schemes
1359	  \[
1360	    t'_{I,J,K} : U^I_J \times_{U^I} U^I_K \longrightarrow U^J_K \times_{U^J} U^J_I ,
1361	  \]
1362	  defined as the composite
1363	  \[
1364	    U^I_J \times_{U^I} U^I_K
1365	      \xrightarrow{\ \sim\ } \Spec S_I
1366	      \xrightarrow{\ \Spec \Theta_{I,J}\ } \Spec S_J
1367	      \xrightarrow{\ \Spec \mathrm{swap}\ } \Spec R^J[1/(P^J_K P^J_I)]
1368	      \xrightarrow{\ \sim\ } U^J_K \times_{U^J} U^J_I ,
1369	  \]
1370	  where the first and last arrows are the pullback identifications of
1371	  \cref{def:gr_away_pullback_iso} -- the source one for the pair \((P^I_J, P^I_K)\)
1372	  over \(R^I\), and the target one (taken inverse) for the pair \((P^J_K, P^J_I)\)
1373	  over \(R^J\) -- the middle arrow is the \(\Spec\) of the localised
1374	  triple-overlap transition \(\Theta_{I,J} : S_J \to S_I\)
1375	  (\cref{def:gr_cocycle_theta_ij}), and \(\mathrm{swap}\) is the \(\Spec\) of the
1376	  order-swap isomorphism \(R^J[1/(P^J_K P^J_I)] \cong S_J = R^J[1/(P^J_I P^J_K)]\)
1377	  (\cref{def:gr_away_mul_comm_equiv}). The order-swap is inserted precisely to
1378	  reconcile the product order \(P^J_K P^J_I\) carried by the target pullback
1379	  identification with the order \(P^J_I P^J_K\) of the codomain \(S_J\) of
1380	  \(\Theta_{I,J}\).
1381	\end{definition}
1382	
1383	\begin{lemma}
1384	[The \(t'\) ring identity]
1385	  \label{lem:gr_chartTransition'_ringIdentity}
1386	  \lean{AlgebraicGeometry.Grassmannian.chartTransition'_ringIdentity}
1387	  \uses{def:gr_cocycle_theta_ij, def:gr_away_mul_comm_equiv, def:gr_away_incl_right, def:gr_away_incl_left, def:gr_transition, lem:gr_awayInclRight_comp_algebraMap, lem:gr_awayMulCommEquiv_comp_algebraMap, lem:mathlib_away_lift}
1388	  Over the triple-overlap rings, the localised transition \(\Theta_{I,J}\)
1389	  (\cref{def:gr_cocycle_theta_ij}) pre-composed with the order-swap and the right
1390	  inclusion equals the left inclusion post-composed with the plain transition
1391	  \(\theta_{I,J}\), as ring homomorphisms \(R^J[1/P^J_I] \to S_I\):
1392	  \[
1393	    \Theta_{I,J} \circ \mathrm{swap} \circ \iota^{\mathrm{R}}_{P^J_K, P^J_I}
1394	      \;=\; \iota^{\mathrm{L}}_{P^I_J, P^I_K} \circ \theta_{I,J} .
1395	  \]
1396	\end{lemma}
1397	\begin{proof}
1398	  \uses{def:gr_cocycle_theta_ij, def:gr_away_mul_comm_equiv, def:gr_away_incl_right, def:gr_away_incl_left, def:gr_transition, lem:gr_awayInclRight_comp_algebraMap, lem:gr_awayMulCommEquiv_comp_algebraMap, lem:mathlib_away_lift}
1399	  Both sides are ring maps out of the away-localisation \(R^J[1/P^J_I]\), so by the
1400	  universal property of the localisation (\cref{lem:mathlib_away_lift}) it suffices
1401	  to check equality after pre-composing with the structure map
1402	  \(R^J \to R^J[1/P^J_I]\), i.e.\ on the chart ring \(R^J\). There the right
1403	  inclusion and the order-swap collapse to structure maps
1404	  (\cref{lem:gr_awayInclRight_comp_algebraMap},
1405	  \cref{lem:gr_awayMulCommEquiv_comp_algebraMap}), and the lift defining
1406	  \(\Theta_{I,J}\) (\cref{def:gr_cocycle_theta_ij}) unwinds to
1407	  \(\iota^{\mathrm{L}} \circ \tilde\theta_{I,J}\)
1408	  (\cref{def:gr_away_incl_left}); the right side likewise unwinds through the lift
1409	  defining \(\theta_{I,J}\) (\cref{def:gr_transition}) to the same
1410	  \(\iota^{\mathrm{L}} \circ \tilde\theta_{I,J}\). Proved directly in Lean.
1411	\end{proof}
1412	
1413	\begin{lemma}
1414	[The \(t'\) compatibility field \(t_{\mathrm{fac}}\)]
1415	  \label{lem:gr_chartTransition'_fac}
1416	  \lean{AlgebraicGeometry.Grassmannian.chartTransition'_fac}
1417	  \uses{def:gr_chart_transition', lem:gr_chartTransition'_ringIdentity, def:gr_away_pullback_iso, lem:gr_awayPullbackIso_inv_fst, lem:gr_awayPullbackIso_inv_snd, def:gr_chart_transition}
1418	  % NOTE: in Lean the `HasPullback` instance diamond on the heavy `MvPolynomial`
1419	  % away-localisation objects blocks keyed `rw`/`simp` on the second-projection
1420	  % leg; it is fired with `erw [awayPullbackIso_inv_snd]`, and the final
1421	  % associativity step is closed by `congrArg (_ ≫ ·)` / `Iso.inv_comp_eq`
1422	  % (defeq inside `exact`) rather than syntactic rewriting.
1423	  The triple-overlap transition \(t'\) (\cref{def:gr_chart_transition'}) is
1424	  compatible with the projections to the charts:
1425	  \[
1426	    \mathrm{pr}_2 \circ t'_{I,J,K} \;=\; t_{I,J} \circ \mathrm{pr}_1 ,
1427	  \]
1428	  where \(\mathrm{pr}_1\) is the first projection of the source pullback
1429	  \(U^I_J \times_{U^I} U^I_K\), \(\mathrm{pr}_2\) the second projection of the
1430	  target pullback \(U^J_K \times_{U^J} U^J_I\), and \(t_{I,J}\) the scheme-level
1431	  transition (\cref{def:gr_chart_transition}).
1432	\end{lemma}
1433	\begin{proof}
1434	  \uses{def:gr_chart_transition', lem:gr_chartTransition'_ringIdentity, def:gr_away_pullback_iso, lem:gr_awayPullbackIso_inv_fst, lem:gr_awayPullbackIso_inv_snd, def:gr_chart_transition}
1435	  Both fibre products are affine, so the identity may be checked after applying
1436	  \(\Spec\), as an identity of the underlying ring homomorphisms. Rewriting the
1437	  source projection \(\mathrm{pr}_1\) through the pullback identification
1438	  (\cref{lem:gr_awayPullbackIso_inv_fst}) and the target projection
1439	  \(\mathrm{pr}_2\) through \cref{lem:gr_awayPullbackIso_inv_snd} turns the claim
1440	  into the ring identity \cref{lem:gr_chartTransition'_ringIdentity}: the three
1441	  localised pieces of \(t'\) (\cref{def:gr_chart_transition'}) collapse to the
1442	  left inclusion followed by the plain transition \(t_{I,J}\)
1443	  (\cref{def:gr_chart_transition}). Proved directly in Lean.
1444	\end{proof}
1445	
1446	\section{The glued Grassmannian scheme}
1447	\label{sec:gr_glued}
1448	
1449	\begin{definition}
1450	[The Grassmannian scheme \(\mathrm{Gr}(r,d)\) over \(\mathbb{Z}\)]
1451	  \label{def:gr_glued_scheme}
1452	  \lean{AlgebraicGeometry.Grassmannian.scheme}
1453	  \uses{def:gr_affine_chart, def:gr_transition, lem:gr_cocycle,
1454	    def:gr_chart_overlap, def:gr_chart_incl, lem:gr_chartIncl_isOpenImmersion,
1455	    lem:gr_chartIncl_self_isIso, def:gr_chart_transition,
1456	    lem:gr_chartTransition_self, def:gr_away_pullback_iso,
1457	    lem:gr_awayPullbackIso_inv_fst, lem:gr_awayPullbackIso_inv_snd,
1458	    def:gr_away_mul_comm_equiv, def:gr_cocycle_theta_ij,
1459	    def:gr_chart_transition', lem:gr_chartTransition'_fac,
1460	    lem:gr_chartTransition'_ringIdentity, lem:gr_cocycle_imageMatrix_eq}
1461	  % NOTE (formalization status): the triple-overlap glue-datum fields are
1462	  % formalized and axiom-clean in Lean -- the `t'`-field
1463	  % (\cref{def:gr_chart_transition'}, Lean `chartTransition'`), its
1464	  % `t_fac`-compatibility (\cref{lem:gr_chartTransition'_fac}, Lean
1465	  % `chartTransition'_fac`), the underlying ring identity
1466	  % (\cref{lem:gr_chartTransition'_ringIdentity}, Lean
1467	  % `chartTransition'_ringIdentity`), and the order-swap helper
1468	  % (\cref{lem:gr_awayMulCommEquiv_comp_algebraMap}). NOT yet formalized: the
1469	  % `cocycle` field, the `Scheme.GlueData` bundle, and `Grassmannian.scheme`
1470	  % itself. The categorical reduction of `cocycle` is solved (the conjugating
1471	  % pullback isomorphisms telescope away); the residual is the rotated ring
1472	  % cocycle identity Phi = id detailed below. The
1473	  % \lean{...AlgebraicGeometry.Grassmannian.scheme} target above therefore does
1474	  % not yet exist in Lean.
1475	  % SOURCE: [Nitsure], \S 1, sub-section "Construction by gluing together
1476	  % affine patches" (read from
1477	  % references/nitsure-hilbert-quot-src/nitsure-hilbert-quot.tex, L843-L850).
1478	  % SOURCE QUOTE:
1479	  % "Therefore the schemes
1480	  %  $U^I$, as $I$ varies over all the
1481	  %  ${r\choose d}$ different
1482	  %  subsets of  $\{ 1,\ldots, r\}$ of cardinality $d$,
1483	  %  can be glued together by the co-cycle $(\theta_{I,J})$ to form a
1484	  %  finite-type scheme $\grass(r,d)$ over $\Z$. As each $U^I$ is
1485	  %  isomorphic to $\AA^{d(r-d)}_{\Z}$, it follows that
1486	  %  $\grass(r,d) \to \spec \Z$ is smooth of relative dimension $d(r-d)$."
1487	  \textit{Source: [Nitsure], \S 1.}
1488	  Gluing the affine charts \(\{U^I\}\) (\cref{def:gr_affine_chart}), one for each
1489	  of the \(\binom{r}{d}\) subsets \(I \subseteq \{1,\dots,r\}\) of cardinality
1490	  \(d\), along the open subschemes \(U^I_J \subseteq U^I\) via the transition
1491	  isomorphisms \(\theta_{I,J} : U^I_J \xrightarrow{\sim} U^J_I\)
1492	  (\cref{def:gr_transition}) -- which satisfy the cocycle condition
1493	  \(\theta_{I,K} = \theta_{J,K} \circ \theta_{I,J}\) and \(\theta_{I,I} = \id\)
1494	  of \cref{lem:gr_cocycle} -- yields a scheme
1495	  \[
1496	    \mathrm{Gr}(r,d) \longrightarrow \Spec \mathbb{Z}.
1497	  \]
1498	  It is of finite type over \(\mathbb{Z}\) (a finite gluing of finitely
1499	  generated \(\mathbb{Z}\)-algebras), and under the gluing each \(U^I\) is an
1500	  open subscheme of \(\mathrm{Gr}(r,d)\) with \(U^I \cap U^J = U^I_J\).
1501	
1502	  \emph{Construction of the glue datum.} The gluing is carried out through the
1503	  Mathlib vehicle for scheme gluing, a glue datum in the sense of a category of
1504	  schemes (the structure \(\mathtt{Scheme.GlueData}\), extending the abstract
1505	  glue-datum interface). Its data are supplied as follows. The index set is the
1506	  set \(J := \{\, I \subseteq \{1,\dots,r\} : \#(I) = d \,\}\) of size-\(d\)
1507	  subsets. The objects are the charts \(U^I\) (\cref{def:gr_affine_chart}); the
1508	  pairwise overlaps are the schemes \(U^I_J\) (\cref{def:gr_chart_overlap}); the
1509	  inclusions \(f_{I,J} : U^I_J \to U^I\) are the open immersions
1510	  \(\cref{def:gr_chart_incl}\) (open immersions by
1511	  \cref{lem:gr_chartIncl_isOpenImmersion}, in particular monomorphisms), with the
1512	  identity field \(f_{\mathrm{id}}\) supplied by
1513	  \cref{lem:gr_chartIncl_self_isIso}; the transition isomorphisms
1514	  \(t_{I,J} : U^I_J \to U^J_I\) are the scheme-level transitions
1515	  \(\cref{def:gr_chart_transition}\), with identity field \(t_{\mathrm{id}}\)
1516	  supplied by \cref{lem:gr_chartTransition_self}.
1517	
1518	  The triple-overlap field \(t'\) and its first coherence obligation are supplied
1519	  by the two preceding results. The field itself is the morphism
1520	  \(t'_{I,J,K} : U^I_J \times_{U^I} U^I_K \to U^J_K \times_{U^J} U^J_I\) of
1521	  \cref{def:gr_chart_transition'}, and the compatibility field
1522	  \(t_{\mathrm{fac}}\) -- that \(t'\) is compatible with the projections to the
1523	  charts -- is \cref{lem:gr_chartTransition'_fac}, which reduces (both fibre
1524	  products being affine) to the ring identity
1525	  \cref{lem:gr_chartTransition'_ringIdentity} via the leg lemmas
1526	  \cref{lem:gr_awayPullbackIso_inv_fst} and \cref{lem:gr_awayPullbackIso_inv_snd}.
1527	
1528	  \emph{The residual cocycle obligation.} What remains is the \(t'\)-cocycle
1529	  field, the coherence
1530	  \[
1531	    t'_{I,J,K} \;\circ\; t'_{J,K,I} \;\circ\; t'_{K,I,J} \;=\; \mathrm{id}
1532	  \]
1533	  on the source triple overlap. Its categorical reduction is already
1534	  achieved: in the threefold composite, each of the two internal pairs of the
1535	  form \(\mathrm{ap}_{X,Y}^{-1} \circ \mathrm{ap}_{X,Y}\) -- the inverse of one
1536	  factor's target pullback identification against the next factor's source
1537	  pullback identification (\cref{def:gr_away_pullback_iso}) -- cancels, the two
1538	  identifications sharing the same instance because all three \(t'\)-factors are
1539	  built from the same construction (\cref{def:gr_chart_transition'}). Stripping
1540	  the outer conjugating pullback isomorphism (its two ends likewise cancel) and
1541	  collapsing the six remaining \(\Spec\)-arrows into a single \(\Spec\) leaves a
1542	  pure ring obligation: the identity of ring homomorphisms
1543	  \[
1544	    \Phi \;=\; \mathrm{id}_{\,R^I[1/(P^I_J P^I_K)]}, \qquad
1545	    \Phi \;:=\; \Theta_{I,J} \circ \mathrm{swap}_J \circ \Theta_{J,K}
1546	      \circ \mathrm{swap}_K \circ \Theta_{K,I} \circ \mathrm{swap}_I ,
1547	  \]
1548	  where \(\Theta_{X,Y}\) is the localised triple-overlap transition
1549	  (\cref{def:gr_cocycle_theta_ij}, taken for the rotated index triple) and each
1550	  \(\mathrm{swap}_X\) is the matching order-swap isomorphism
1551	  (\cref{def:gr_away_mul_comm_equiv}). This is a rotated analogue of the ring
1552	  cocycle condition \cref{lem:gr_cocycle}: it is proved by
1553	  reducing -- via the universal property of the away-localisation, applied to the
1554	  generators \(\mathrm{powers}(P^I_J P^I_K)\) -- to the chart-ring generators, and
1555	  then reusing the image-matrix cocycle computation
1556	  \cref{lem:gr_cocycle_imageMatrix_eq} (the same \((Y_K)^{-1} Y\) collapse that
1557	  underlies \cref{lem:gr_cocycle}). With this field in hand the glue datum is
1558	  complete: it is the structure \(\mathtt{Scheme.GlueData}\) with
1559	  \(U := \texttt{affineChart}\) (\cref{def:gr_affine_chart}),
1560	  \(V := \texttt{chartOverlap}\) (\cref{def:gr_chart_overlap}),
1561	  \(f := \texttt{chartIncl}\) (\cref{def:gr_chart_incl}),
1562	  \(t := \texttt{chartTransition}\) (\cref{def:gr_chart_transition}),
1563	  \(t_{\mathrm{id}} := \texttt{chartTransition\_self}\)
1564	  (\cref{lem:gr_chartTransition_self}),
1565	  \(t' := \texttt{chartTransition'}\) (\cref{def:gr_chart_transition'}),
1566	  \(t_{\mathrm{fac}} := \texttt{chartTransition'\_fac}\)
1567	  (\cref{lem:gr_chartTransition'_fac}), and the cocycle field above. The glued
1568	  scheme \(\mathrm{Gr}(r,d)\) is then the colimit
1569	  \((\text{glue datum}).\mathrm{glued}\) produced by the gluing machine.
1570	
1571	  Moreover \(\mathrm{Gr}(r,d) \to \Spec \mathbb{Z}\) is \emph{smooth of relative
1572	  dimension \(d(r-d)\)}. Smoothness and relative dimension are local on the
1573	  source; the charts \(\{U^I\}\) cover \(\mathrm{Gr}(r,d)\), and each
1574	  \(U^I \cong \mathbb{A}^{d(r-d)}_{\mathbb{Z}}\) (\cref{def:gr_affine_chart}) is
1575	  affine space of dimension \(d(r-d)\) over \(\mathbb{Z}\), which is smooth over
1576	  \(\mathbb{Z}\) of relative dimension \(d(r-d)\) (the polynomial ring
1577	  \(\mathbb{Z}[x_1, \dots, x_{d(r-d)}]\) is a smooth \(\mathbb{Z}\)-algebra). As
1578	  the property may be checked on an open cover of the source, the conclusion
1579	  follows.
1580	\end{definition}
