1582	\section{Separatedness}
1583	\label{sec:gr_separated}
1584	
1585	\begin{lemma}
1586	[\(\mathrm{Gr}(r,d)\) is separated over \(\mathbb{Z}\)]
1587	  \label{lem:gr_separated}
1588	  \lean{AlgebraicGeometry.Grassmannian.isSeparated}
1589	  \uses{def:gr_glued_scheme, def:gr_transition}
1590	  % SOURCE: [Nitsure], \S 1, sub-section "Separatedness" (read from
1591	  % references/nitsure-hilbert-quot-src/nitsure-hilbert-quot.tex, L856-L860).
1592	  % SOURCE QUOTE:
1593	  % "The intersection of the diagonal of $\grass(r,d)$ with $U^I\times U^J$
1594	  %  can be seen to be the closed subscheme $\Delta_{I,J}\subset U^I\times U^J$
1595	  %  defined by entries of the matrix formula $X^J_I\,X^I - X^J =0$,
1596	  %  and so $\grass(r,d)$ is a separated scheme."
1597	  \textit{Source: [Nitsure], \S 1.}
1598	  The structure morphism \(\mathrm{Gr}(r,d) \to \Spec \mathbb{Z}\)
1599	  (\cref{def:gr_glued_scheme}) is separated; equivalently, the diagonal
1600	  \(\Delta : \mathrm{Gr}(r,d) \to \mathrm{Gr}(r,d) \times_{\mathbb{Z}}
1601	  \mathrm{Gr}(r,d)\) is a closed immersion.
1602	\end{lemma}
1603	
1604	% SOURCE QUOTE PROOF: "The intersection of the diagonal of $\grass(r,d)$ with
1605	% $U^I\times U^J$ can be seen to be the closed subscheme
1606	% $\Delta_{I,J}\subset U^I\times U^J$ defined by entries of the matrix formula
1607	% $X^J_I\,X^I - X^J =0$, and so $\grass(r,d)$ is a separated scheme."
1608	% (references/nitsure-hilbert-quot-src/nitsure-hilbert-quot.tex, L856-L860.)
1609	\begin{proof}
1610	  \uses{def:gr_glued_scheme, def:gr_transition}
1611	  The products \(U^I \times_{\mathbb{Z}} U^J\), as \(I, J\) range over the
1612	  size-\(d\) subsets, form an affine open cover of \(\mathrm{Gr}(r,d)
1613	  \times_{\mathbb{Z}} \mathrm{Gr}(r,d)\). Separatedness may be checked on this
1614	  cover: it suffices to show that for each pair \((I,J)\) the preimage
1615	  \(\Delta^{-1}(U^I \times_{\mathbb{Z}} U^J)\) maps by a closed immersion into
1616	  \(U^I \times_{\mathbb{Z}} U^J\), i.e.\ that the corresponding ring
1617	  homomorphism is surjective.
1618	
1619	  By \cref{def:gr_glued_scheme} the diagonal preimage is the overlap
1620	  \(\Delta^{-1}(U^I \times_{\mathbb{Z}} U^J) = U^I \cap U^J = U^I_J = \Spec
1621	  \mathbb{Z}[X^I, 1/P^I_J]\). The restricted diagonal corresponds to the ring map
1622	  \[
1623	    \delta_{I,J} : \mathbb{Z}[X^I] \otimes_{\mathbb{Z}} \mathbb{Z}[X^J]
1624	    \longrightarrow \mathbb{Z}[X^I, 1/P^I_J],
1625	    \qquad
1626	    X^I \otimes 1 \mapsto X^I, \quad 1 \otimes X^J \mapsto (X^I_J)^{-1} X^I,
1627	  \]
1628	  the second component being the comorphism \(\theta_{I,J}\) of
1629	  \cref{def:gr_transition} (a point of \(U^I_J\) and its image under
1630	  \(\theta_{I,J}\) are the two coordinates of a point of the diagonal). We claim
1631	  \(\delta_{I,J}\) is surjective. Its image contains all entries of \(X^I\)
1632	  (from the first factor). From the second factor it contains the entries of
1633	  \((X^I_J)^{-1} X^I\); taking the \(I\)-minor of this matrix, and using
1634	  \(X^I_I = 1_{d\times d}\), the image contains the entries of \((X^I_J)^{-1}\),
1635	  and in particular
1636	  \[
1637	    \delta_{I,J}(1 \otimes P^J_I) = \det\bigl((X^I_J)^{-1}\bigr) = 1/P^I_J .
1638	  \]
1639	  Hence \(1/P^I_J\) lies in the image, so the image is all of
1640	  \(\mathbb{Z}[X^I, 1/P^I_J]\) and \(\delta_{I,J}\) is surjective. Concretely the
1641	  closed subscheme \(\Delta_{I,J} \subseteq U^I \times_{\mathbb{Z}} U^J\) is cut
1642	  out by the entries of the matrix relation
1643	  \[
1644	    X^J_I \, X^I - X^J \;=\; 0,
1645	  \]
1646	  which on the diagonal holds because \(X^J = (X^I_J)^{-1} X^I\) forces
1647	  \(X^J_I = (X^I_J)^{-1} X^I_I = (X^I_J)^{-1}\) and therefore \(X^J_I X^I =
1648	  (X^I_J)^{-1} X^I = X^J\). As each restricted diagonal is a closed immersion,
1649	  \(\Delta\) is a closed immersion and \(\mathrm{Gr}(r,d)\) is separated over
1650	  \(\mathbb{Z}\).
1651	\end{proof}
